async function createRequestForAuthjs(
  event: H3Event,
  runtimeConfig: RuntimeConfig,
  trustHostUserPreference: boolean
): Promise<RequestInternal> {
  const nextRequest: Omit<RequestInternal, 'action'> = {
    // `authjs` expects the baseURL here despite the param name
    host: getHostValueForAuthjs(event, runtimeConfig, trustHostUserPreference, isProduction),
    body: undefined,
    cookies: parseCookies(event),
    query: undefined,
    headers: getHeaders(event),
    method: event.method,
    providerId: undefined,
    error: undefined
  }

  // Figure out what action, providerId (optional) and error (optional) of the NextAuth.js lib is targeted
  const query = getQuery(event)
  const { action, providerId } = parseActionAndProvider(event)
  const error = query.error
  if (Array.isArray(error)) {
    throw createError({ statusCode: 400, message: 'Error query parameter can only appear once' })
  }

  // Parse a body if the request method is supported, use `undefined` otherwise
  const body = isMethod(event, ['PATCH', 'POST', 'PUT', 'DELETE'])
    ? await readBody(event)
    : undefined

  return {
    ...nextRequest,
    body,
    query,
    action,
    providerId,
    error: error ? String(error) : undefined
  }
}

export async function refreshUserAccessToken(tokensByUser: TokensByUser, refreshToken: string): Promise<UserTokens | undefined> {
  // Get the access token
  const oldAccessToken = tokensByUser.refresh.get(refreshToken)
  if (!oldAccessToken) {
    return
  }

  // Invalidate old access token
  invalidateAccessToken(tokensByUser, oldAccessToken)

  // Get the user data. In a real implementation this is likely a DB call.
  // In this demo we simply re-use the existing JWT data
  const jwtUser = await decodeToken(refreshToken)
  if (!jwtUser) {
    return
  }

  const user = userSchema.safeParse(jwtUser)
  if (!user.success) {
    return
  }

  const accessToken = await createSignedJwt({ ...user.data, scope: ['test', 'user'] }, /* 5 minutes */ 60 * 5)
  tokensByUser.refresh.set(refreshToken, accessToken)
  tokensByUser.access.set(accessToken, refreshToken)

  return Promise.resolve({
    accessToken,
    refreshToken
  })
}
